package com.finguard.audit.service;import com.finguard.audit.domain.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.*;
@Service public class AuditService {private final AuditEventRepository events;public AuditService(AuditEventRepository events){this.events=events;}@Transactional public void record(UUID eventId,UUID transactionId,String type,String payload){if(!events.existsBySourceEventId(eventId))events.save(new AuditEvent(eventId,transactionId,type,payload));}public List<AuditEvent> byTransaction(UUID id){return events.findByTransactionIdOrderByCreatedAtAsc(id);}public List<AuditEvent> recent(){return events.findTop200ByOrderByCreatedAtDesc();}}
